install style manager ƒ:
() => {
    const styleIdFromKey = (k) => {
        const base = String(k).replace(/\s*\{$/, "").trim();
        return 'diarsaba-style-' + base.replace(/[^\w-]/g, '_').replace(/^_+|_+$/g, '');
    };

    // crear inicialmente las etiquetas <style> para claves que terminen en '{'
    for (const [k, v] of diarsaba.entries()) {
        if (typeof k === 'string' && k.endsWith('{')) {
            const id = styleIdFromKey(k);
            if (!document.getElementById(id)) {
                const el = document.createElement('style');
                el.id = id;
                el.textContent = typeof v === 'string' ? v : '';
                document.head.appendChild(el);
            }
        }
    }

    // override diarsaba.set para mantener sincronizados los estilos
    const originalSet = diarsaba.set.bind(diarsaba);
    diarsaba.set = (key, value) => {
        originalSet(key, value);
        try {
            if (typeof key === 'string' && key.endsWith('{')) {
                const id = styleIdFromKey(key);
                let el = document.getElementById(id);
                if (el) el.textContent = typeof value === 'string' ? value : '';
                else {
                    el = document.createElement('style');
                    el.id = id;
                    el.textContent = typeof value === 'string' ? value : '';
                    document.head.appendChild(el);
                }
            }
        } catch (e) { console.error('install style manager error', e); }
        return diarsaba;
    };
}

guardar ! ƒ:
async () => {
    // No persistir refs DOM (claves terminadas en ֎) ni objetos vivos de
    // runtime: se regeneran solos y solo ensucian el archivo (y provocan
    // entradas {} que rompen código que espera un elemento).
    const skipKeys = new Set([
        "ws socket",
        "Streams #",
        "current menu",
        "current chip menu",
        "pointer up event",
        "pointer down event",
        "pointer move event"
    ]);

    const dataToSave = {};
    for (const [key, value] of diarsaba.entries()) {
        if (key.endsWith("֎") || skipKeys.has(key)) continue;

        if (key.endsWith("ƒ")) {
            dataToSave[key] = String(value).replace(/\r\n/g, "\n").trim();
        } else {
            dataToSave[key] = value;
        }
    }
    const jsonString = JSON.stringify(dataToSave, null, 2);

    try {
        const savedPath = await SavePredefinedFunctions(jsonString);
        console.log("Archivo guardado exitosamente en:", savedPath);
    } catch (error) {
        console.error("Error al guardar el archivo:", error);
    }
}

show context menu ƒ:
() => {
    // Con el modo mover activo el chip se arrastra, no se abre.
    if (diarsaba.get("moviendo chips §")) return;

    const event = diarsaba.get("pointer up event");

    // Los modales (editor Monaco, modal de nombre, botón de mover) viven
    // ENCIMA del lienzo, pero este manejador escucha toda la ventana. Sin
    // esto, un doble clic dentro del editor se lee como doble clic en un
    // chip: el título del modal ES el nombre del átomo, sigilo incluido.
    if (event.target.closest && event.target.closest(".editor-overlay, .modal-content, .mover-chips-btn")) return;

    if (event.target.nodeName === "HTML" || event.target.nodeName === "BODY") {
        const currentMenu = diarsaba.get("current menu");
        if (currentMenu && typeof currentMenu.remove === "function") {
                        currentMenu.remove();
        }

        diarsaba.set(
            "current menu",
            diarsaba.get("create list menu ƒ")(diarsaba.get("atom name list #"))
        );

        diarsaba.set("open x $", event.clientX);
        diarsaba.set("open y $", event.clientY);
    } else {
        const type = event.target.textContent.slice(-1);
        const name = event.target.textContent;

        diarsaba.get("show options list ƒ")(type, name);
    }
}

show options list ƒ:
(type, name) => {
    // 1. Limpiar el menú anterior si existe
    const currentMenu = diarsaba.get("current chip menu");
    if (currentMenu instanceof Element) {
        currentMenu.remove();
    }

    // 2. Obtener los recursos compartidos que usan todas las ramas
    const event = diarsaba.get("pointer up event");
    const createMenu = diarsaba.get("create list menu ƒ");
    const target = event.target;

    // Variables que determinarán cómo se creará el menú
    let menuOptions;
    let menuArgs = [];

    // 3. Determinar las opciones y argumentos según el caso
    if (/^\[\d+\]/.test(name)) {
        menuOptions = diarsaba.get("list option [] #");
        menuArgs = [target.parentElement.dataset.parent, name];
    } else if (diarsaba.get("types list #").includes(type)) {
        menuOptions = diarsaba.get(`list option ${type} #`);
        menuArgs = [name];
    } else {
        const fallbackType = "֎";
        const parentDataset = target.dataset.parent;
        const lastChar = parentDataset.slice(-1);

        menuOptions = diarsaba.get(`list option ${fallbackType} ${lastChar} #`);
        menuArgs = [parentDataset];
    }

    // 4. Crear y guardar el nuevo menú en un solo lugar
    const newMenu = createMenu(menuOptions, ...menuArgs);
    diarsaba.set("current chip menu", newMenu);
}

handle click ƒ:
async () => {
    // Con el modo mover activo el chip se arrastra, no se abre.
    if (diarsaba.get("moviendo chips §")) return;

    // 1. Obtener el evento y el elemento clickeado
    const event = diarsaba.get("pointer up event");
    const target = event.target;

    // Los modales (editor Monaco, modal de nombre, botón de mover) viven
    // ENCIMA del lienzo, pero este manejador escucha toda la ventana. Sin
    // esto, un doble clic dentro del editor se lee como doble clic en un
    // chip: el título del modal ES el nombre del átomo, sigilo incluido.
    if (event.target.closest && event.target.closest(".editor-overlay, .modal-content, .mover-chips-btn")) return;
    const nodeName = target.nodeName;

    // 2. Si se hizo clic en el fondo (HTML/BODY), solo limpiar menús
    if (nodeName === "HTML" || nodeName === "BODY") {
        diarsaba.get("clear menus ƒ")();
        return;
    }

    const content = target.textContent;
    const clearMenus = () => diarsaba.get("clear menus ƒ")(); // función auxiliar para limpiar

    // 3. Caso especial: "guardar !"
    if (content === "@ place") {
        diarsaba.get("new place ƒ")()
        clearMenus();
        return
    }

    if (content === "guardar !") {
        const guardarFn = diarsaba.get("guardar ! ƒ");
        if (guardarFn) guardarFn();
        clearMenus();
        return;
    }

    if (content === "reload !") {
        window.location.reload();
        return;
    }



    // 4. Obtener referencias comunes
    const atomList = diarsaba.get("atom name list #");
    const parentDataset = target.parentElement.dataset;

    // 5. Si el contenido pertenece a la lista de átomos → crear nuevo elemento
    if (atomList.includes(content)) {
        // Eliminar menú actual si existe
        const currentMenu = diarsaba.get("current menu");
        if (currentMenu) currentMenu.remove();

        // Pedir nombre mediante un modal (usa la primera letra como pista)
        const name = await diarsaba.get("modal input ƒ")(content.slice(0, 1));

        // Solo proceder si se ingresó un nombre válido
        if (name != null && name !== "") {


            diarsaba.get("add to place ƒ")(name)
            // Ejecutar la función de creación correspondiente al tipo de átomo
            const createFn = diarsaba.get(`create ${content} ƒ`);
            createFn(name);

            // Crear el chip visual asociado
            const chip = diarsaba.get("create chip ƒ")(
                diarsaba.get("open x $"),
                diarsaba.get("open y $"),
                name,
                "",
                content.slice(0, 1) // letra inicial como categoría
            );

            // Guardar referencia del chip en el almacenamiento global
            diarsaba.set(`${name} ֎`, chip);
        }
        clearMenus();
        return;
    }

    // 6. Solo si es un ÍTEM de lista con formato "[número] texto".
    // Ojo: no basta con que contenga corchetes — opciones como "· []* ocultar"
    // los llevan en su etiqueta y caían aquí, donde el parseo fallaba en
    // silencio y nunca se ejecutaban.
    if (/^\[\d+\]/.test(content)) {
        try {
            const parsed = diarsaba.get("obtener index [0] ƒ")(content);
            const label = parsed.texto;

            // Despacho por sigilo: el ítem "cobra vida" según su tipo
            // (! ~ ejecutan, # abre sublista, ƒ corre). Si no lo maneja,
            // se cae al comportamiento anterior (función con ese nombre).
            const dispatch = diarsaba.get("dispatch item ƒ");
            const handled = dispatch ? dispatch(label, parentDataset, target) : false;
            if (!handled) {
                const fn = diarsaba.get(`${label} ƒ`) || diarsaba.get(`${content} ƒ`);
                if (fn) {
                    fn(parentDataset);
                }
            }
        } catch (err) {
            // Si el parseo falla, simplemente se ignora
        }
        clearMenus();
        return;
    }

    //otro caso

    let last_click = diarsaba.get("last click on §")
    if (last_click == undefined || last_click == null) {
        diarsaba.set("last click on §", content)
    } else {
        if (last_click == content) {
            if(content.slice(-1) == "@"){
                diarsaba.get("on double tap place ƒ")()
            }else{
                const editables = diarsaba.get("editables list #")
                if (editables.includes(content.slice(-1))){

                    diarsaba.get("open general editor ƒ")(content)
                }
            }
            diarsaba.set("last click on §", null)
        } else {
            diarsaba.set("last click on §", content)
        }
    }


    // 7. Caso general: el contenido corresponde directamente a una función
    //revisar por que se agrega ƒ o para que casos servia
    const generalFn = diarsaba.get(`${content} ƒ`);
    if (generalFn) {
        generalFn(parentDataset);
    }
    clearMenus();
}

