· * quitar ƒ:
(dataset) => {
    // Saca el chip del place actual y del DOM. El ÁTOMO permanece en diarsaba
    // (puede volver a colocarse en otro place o seguir siendo referenciado).
    const name = dataset.parent;

    // 1. Quitar chips del DOM (principal e hijos abiertos) y sus referencias
    [`${name} ֎`, `${name} ֎ ֎`, `${name} # ֎`].forEach((k) => {
        const el = diarsaba.get(k);
        if (el && typeof el.remove === "function") el.remove();
        diarsaba.delete(k);
    });

    // 2. Quitar la entrada del place actual (para que no reaparezca al recargar)
    const placeName = diarsaba.get("current place §");
    const place = diarsaba.get(placeName);
    if (place && typeof place === "object") {
        const { [name]: _omit, ...rest } = place;
        diarsaba.set(placeName, rest);
    }
}

· * eliminar ƒ:
(dataset) => {
    // Borrado DEFINITIVO: elimina el átomo de diarsaba, sus chips del DOM y
    // todas las referencias en cualquier place.
    const name = dataset.parent;

    // 1. Quitar chips del DOM (principal y posibles hijos abiertos) y sus refs
    [`${name} ֎`, `${name} ֎ ֎`, `${name} # ֎`].forEach((k) => {
        const el = diarsaba.get(k);
        if (el && typeof el.remove === "function") el.remove();
        diarsaba.delete(k);
    });

    // 2. Quitar la referencia de TODOS los places que lo contengan
    for (const [k, v] of diarsaba.entries()) {
        if (typeof k === "string" && k.endsWith("@") && v && typeof v === "object") {
            if (Object.prototype.hasOwnProperty.call(v, name)) {
                const { [name]: _omit, ...rest } = v;
                diarsaba.set(k, rest);
            }
        }
    }

    // 3. Borrar el átomo de diarsaba (definitivo)
    diarsaba.delete(name);
}

