    // Si el chip no está visible, anclamos al puntero en vez de reventar.
    const chip_ancla = diarsaba.get(`${dataset.parent} ֎`);
    const rect = (chip_ancla instanceof Element)
        ? chip_ancla.getBoundingClientRect()
