() => {
    // Guard: los defaults serializados pueden ser {} (truthy sin .remove)
    const menu = diarsaba.get("current menu");
    if (menu && typeof menu.remove === "function") menu.remove();

    const chipMenu = diarsaba.get("current chip menu");
    if (chipMenu && typeof chipMenu.remove === "function") chipMenu.remove();
}

dispatch item ƒ:
(name, dataset, target) => {
    // Un ítem de lista "cobra vida" según su sigilo. Devuelve true si lo
    // manejó (y así handle click ƒ no aplica el fallback anterior).
    const type = name.slice(-1);

    // Acciones y threads: ejecutar
    if (type === "!" || type === "~") {
        threads(name);
        return true;
    }

    // Listas: abrir su contenido como sublista efímera (con scroll) junto al ítem
    if (type === "#") {
        const list = diarsaba.get(name);
        if (!Array.isArray(list)) return false;
        const prev = diarsaba.get(`${name} # ֎`);
        if (prev && typeof prev.remove === "function") prev.remove();
        const rect = target.getBoundingClientRect();
        const sub = diarsaba.get("create list ƒ")(rect.right + 6, rect.top, list, name);
        diarsaba.set(`${name} # ֎`, sub);
        return true;
    }

    // Funciones: ejecutar
    if (type === "ƒ") {
        const f = diarsaba.get(name);
        if (typeof f === "function") {
            f(dataset);
            return true;
        }
        return false;
    }

    return false;
}

modal input ƒ:
async (pre) => {
    const createEl = (tag, props = {}) =>
        Object.assign(document.createElement(tag), props);

    const div = createEl("div", { className: "modal-content" });
    const input = createEl("input", {
        type: "text",
        value: pre || "",
        spellcheck: false,
    });

    const buttonContainer = createEl("div", { className: "modal-buttons" });

    ["Cancel", "Continue"].forEach((text) => {
        const btn = createEl("button", { textContent: text });
        btn.dataset.modal = text.toLowerCase();
        btn.onclick = () => {
            div.remove();
            this.nombreInputPromise?.(
                text === "Cancel" ? null : input.value.trim()
            );
        };
        buttonContainer.append(btn);
    });

    div.append(input, buttonContainer);
    document.body.append(div);
    input.focus();

    return await new Promise((resolve) => (this.nombreInputPromise = resolve));
}

clamp to viewport ƒ:
(el) => {
    // Reposiciona el elemento para que no se salga de la ventana (clamp).
    // Se mide el tamaño natural en (0,0): si se coloca desbordando, el ancho
    // shrink-to-fit del .context-menu se comprime y daría una medida errónea.
    const margin = 8;
    const vw = window.innerWidth;
    const vh = window.innerHeight;

    const desiredLeft = parseFloat(el.style.left) || 0;
    const desiredTop = parseFloat(el.style.top) || 0;

    el.style.left = "0px";
    el.style.top = "0px";
    const w = el.offsetWidth;
    const h = el.offsetHeight;

    let left = desiredLeft;
    let top = desiredTop;

    if (left + w > vw - margin) left = vw - margin - w;
    if (top + h > vh - margin) top = vh - margin - h;
    if (left < margin) left = margin;
    if (top < margin) top = margin;

    el.style.left = `${left}px`;
    el.style.top = `${top}px`;
}

create list ƒ:
(x, y, list, parent) => {
    const div = document.createElement("div");
    div.classList = "context-menu";

    if (list.length == 0) {
        div.innerHTML += `<span class="menu-item">[0]</span>`;
    } else {
        for (const key in list) {
            div.innerHTML += `<span class="menu-item">[${key}] ${list[key]}</span>`;
        }
    }

    div.style.left = `${x}px`;
    div.style.top = `${y}px`;
    div.dataset.parent = parent;
    document.body.appendChild(div);
    diarsaba.get("clamp to viewport ƒ")(div);
    return div;
}

