() => {
    const socket = diarsaba.get('ws socket');
    if (socket && socket.readyState === WebSocket.OPEN) return;

    const protocol = window.location.protocol === 'https:' ? 'wss' : 'ws';
    const wsUrl = protocol + '://' + window.location.host + '/ws'; // ajusta si es diferente
    const newSocket = new WebSocket(wsUrl);
    newSocket.binaryType = 'arraybuffer';

    newSocket.onopen = () => {
        diarsaba.set('ws state §', 'conectado');
        diarsaba.set('ws socket', newSocket);
        //threads('ws open !'); // por si quieres enganchar otras acciones
    };

    newSocket.onclose = () => {
        diarsaba.set('ws state §', 'desconectado');
        //threads('ws close !');
        // Reintentar después de 1.2s
        setTimeout(() => {
            diarsaba.set('ws state §', 'reconectando');
            diarsaba.get('connect ws ƒ')();
        }, 1200);
    };

    newSocket.onmessage = (event) => {
        const buffer = new Uint8Array(event.data);
        const handler = diarsaba.get('handle entry ws ƒ');
        if (handler) handler(buffer);
    };

    diarsaba.set('ws socket', newSocket);
    diarsaba.set('ws state §', 'conectando');
}

