OpenStream ƒ:
async (arg) => {
    const out = diarsaba.get("p2p out ƒ");
    try {
        // Un string es "me llaman desde código con el peer resuelto": se
        // devuelve el stream y decide quien llama. CUALQUIER otra cosa es un
        // clic — y ojo: una acción ! llega sin argumentos (threads no pasa
        // ninguno), no con el dataset. Por eso no se puede preguntar por
        // typeof arg === "object": eso dejaba fuera justo el caso normal.
        const desdeCodigo = typeof arg === "string" && arg !== "";
        const peer = await diarsaba.get("p2p peer ƒ")(arg);
        if (!peer) return;

        // El mensaje se pide ANTES de conectar. Si el otro lado no está,
        // OpenStream tarda hasta 30 s en rendirse, y preguntar después de esa
        // espera parece que la app se colgó.
        let msg;
        if (!desdeCodigo) {
            msg = await diarsaba.get("modal input ƒ")("hola desde diarsaba");
            if (msg == null || msg === "") return;
        }

        const stream = diarsaba.get("p2p stream ƒ")(await window.p2p.OpenStream(peer, 30000), peer);
        if (desdeCodigo) {
            out("OpenStream", `stream ${stream.id} abierto hacia ${peer.slice(-8)}`);
            return stream;
        }

        await stream.write(msg);
        await stream.done();
        const reply = await stream.read();
        await stream.close();
        return out("OpenStream", `→ ${msg}\n← ${reply}`);
    } catch (e) {
        return out("OpenStream ✗", e);
    }
}

SetStreamHandler ƒ:
async (arg) => {
    const out = diarsaba.get("p2p out ƒ");
    try {
        // Del backend llega un aviso ({from, stream}), no el stream: esto
        // suscribe una sola vez y deja que "p2p on stream ƒ" decida qué se
        // responde. Pasa una función para cambiar el trato desde código.
        if (typeof arg === "function") diarsaba.set("p2p on stream ƒ", arg);
        if (diarsaba.get("p2p handler ֎")) return out("SetStreamHandler", "ya estaba escuchando");

        // La clave ֎ no se persiste: la suscripción vive solo en esta sesión.
        diarsaba.set(
            "p2p handler ֎",
            window.EventsOn("p2p:stream", async (ev) => {
                const stream = diarsaba.get("p2p stream ƒ")(ev.stream, ev.from);
                try {
                    const handler = diarsaba.get("p2p on stream ƒ");
                    if (typeof handler === "function") await handler(stream);
                    else await stream.close();
                } catch (e) {
                    console.error("[p2p] el handler de stream falló", e);
                    await stream.close();
                }
            })
        );

        // Sin nodo arrancado nadie puede llamarnos.
        const me = await window.p2p.Start();
        return out("SetStreamHandler", `escuchando streams entrantes como ${me.slice(-8)}`);
    } catch (e) {
        return out("SetStreamHandler ✗", e);
    }
}

