p2p stream ƒ:
(id, from) => {
    // Un Stream no es serializable, así que se queda en Go y aquí llega su
    // identificador. Esto lo envuelve en algo con lo que se pueda hablar.
    // Los bytes viajan en base64 porque para la librería son opacos; aquí se
    // traducen a texto, que es lo que se teclea en el editor.
    const toB64 = (text) => {
        const bytes = new TextEncoder().encode(text);
        let bin = "";
        for (const b of bytes) bin += String.fromCharCode(b);
        return btoa(bin);
    };
    const fromB64 = (b64) =>
        new TextDecoder().decode(Uint8Array.from(atob(b64), (c) => c.charCodeAt(0)));

    return {
        id,
        from: from || "",
        write: async (text) => await window.p2p.StreamWrite(id, toB64(text)),
        // Termina de hablar sin cerrar: el otro lado lee hasta EOF y contesta
        // por el mismo stream.
        done: async () => await window.p2p.StreamCloseWrite(id),
        read: async (timeoutMs) => {
            let text = "";
            for (;;) {
                const chunk = await window.p2p.StreamRead(id, 0, timeoutMs || 0);
                if (chunk.data) text += fromB64(chunk.data);
                if (chunk.eof) break;
            }
            return text;
        },
        close: async () => await window.p2p.StreamClose(id),
    };
}

