hablar por ƒ:
(id, de) => {
    // Un stream vive en Go; aquí llega su identificador. Esto lo envuelve en
    // algo con lo que hablar. Los bytes van en base64 porque para la librería
    // son opacos.
    const aB64 = (t) => {
        const bytes = new TextEncoder().encode(t);
        let bin = "";
        for (const b of bytes) bin += String.fromCharCode(b);
        return btoa(bin);
    };
    const deB64 = (b) => new TextDecoder().decode(Uint8Array.from(atob(b), (c) => c.charCodeAt(0)));

    return {
        id,
        de: de || "",
        escribir: async (t) => await window.p2p.StreamWrite(id, aB64(t)),
        // Termina de hablar sin cerrar: el otro lado lee hasta el final y contesta.
        termine: async () => await window.p2p.StreamCloseWrite(id),
        leer: async () => {
            let t = "";
            for (;;) {
                const c = await window.p2p.StreamRead(id, 0, 0);
                if (c.data) t += deB64(c.data);
                if (c.eof) break;
            }
            return t;
        },
        cerrar: async () => await window.p2p.StreamClose(id),
    };
}

