                        const hora = new Date().toLocaleTimeString();
                        const previas = diarsaba.get("entradas #") || [];
                        // Lo nuevo arriba, y con techo: esto crece solo y se guarda.
                        diarsaba.set("entradas #", [`[${hora}] ${ev.from.slice(-8)}: ${msg}`, ...previas].slice(0, 100));
                        await s.escribir(`recibido: ${msg}`);
                    } catch (e) {
                        console.error("[p2p] una entrada falló", e);
                    }
                    await s.cerrar();
                })
            );
        }
        await window.p2p.Start();
        if (!callado) dice("ESCUCHANDO.\n\nLo que te llegue aparece en «entradas #».");
    } catch (e) {
        if (!callado) dice(`NO PUDE ESCUCHAR:\n${e.message || e}`);
    }
}

