enviar ƒ:
async () => {
    const dice = diarsaba.get("p2p dice ƒ");
    let s = null;
    try {
        const peer = diarsaba.get("a quien le hablo §");
        if (!peer) return dice("PRIMERO BUSCA A ALGUIEN.\n\nUsa «buscar !» y luego vuelve aquí.");

        // El mensaje se pide ANTES de conectar: conectar puede tardar 30 s, y
        // preguntar después de esa espera parece que la app se colgó.
        const msg = await diarsaba.get("modal input ƒ")("hola");
        if (!msg) return;

        s = diarsaba.get("hablar por ƒ")(await window.p2p.OpenStream(peer, 30000), peer);
        await s.escribir(msg);
        await s.termine();
        const respuesta = await s.leer();
        await s.cerrar();
        return dice(`ENVIÉ: ${msg}\n\nCONTESTÓ: ${respuesta}`);
    } catch (e) {
        if (s) {
            try {
                await s.cerrar();
            } catch (_) {}
        }
        return dice(
            `NO PUDE HABLAR CON ESE NODO:\n${e.message || e}\n\nLo más probable: la otra app se cerró. Vuelve a «buscar !».`
        );
    }
}

